# rcpp models ----
## Setup ----
n_years <- 10
n_ages <- 5
n_lengths <- 8

## IO correctness ----

### CatchAtAgePopulationDerivedQuantities ----
test_that("CatchAtAgePopulationDerivedQuantities Initialize resizes all fields correctly", {
  pop_dq <- methods::new(CatchAtAgePopulationDerivedQuantities)
  pop_dq$Initialize(n_years, n_ages)

  #' @description Test that Initialize resizes total_landings_weight to n_years.
  expect_equal(length(pop_dq$total_landings_weight), n_years)
  #' @description Test that Initialize resizes total_landings_numbers to n_years.
  expect_equal(length(pop_dq$total_landings_numbers), n_years)
  #' @description Test that Initialize resizes mortality_F to n_years * n_ages.
  expect_equal(length(pop_dq$mortality_F), n_years * n_ages)
  #' @description Test that Initialize resizes mortality_M to n_years * n_ages.
  expect_equal(length(pop_dq$mortality_M), n_years * n_ages)
  #' @description Test that Initialize resizes mortality_Z to n_years * n_ages.
  expect_equal(length(pop_dq$mortality_Z), n_years * n_ages)
  #' @description Test that Initialize resizes numbers_at_age to (n_years + 1) * n_ages.
  expect_equal(length(pop_dq$numbers_at_age), (n_years + 1) * n_ages)
  #' @description Test that Initialize resizes unfished_numbers_at_age to (n_years + 1) * n_ages.
  expect_equal(length(pop_dq$unfished_numbers_at_age), (n_years + 1) * n_ages)
  #' @description Test that Initialize resizes biomass to n_years + 1.
  expect_equal(length(pop_dq$biomass), n_years + 1)
  #' @description Test that Initialize resizes spawning_biomass to n_years + 1.
  expect_equal(length(pop_dq$spawning_biomass), n_years + 1)
  #' @description Test that Initialize resizes unfished_biomass to n_years + 1.
  expect_equal(length(pop_dq$unfished_biomass), n_years + 1)
  #' @description Test that Initialize resizes unfished_spawning_biomass to n_years + 1.
  expect_equal(length(pop_dq$unfished_spawning_biomass), n_years + 1)
  #' @description Test that Initialize resizes proportion_mature_at_age to (n_years + 1) * n_ages.
  expect_equal(length(pop_dq$proportion_mature_at_age), (n_years + 1) * n_ages)
  #' @description Test that Initialize resizes expected_recruitment to n_years + 1.
  expect_equal(length(pop_dq$expected_recruitment), n_years + 1)
  #' @description Test that Initialize resizes sum_selectivity to n_years * n_ages.
  expect_equal(length(pop_dq$sum_selectivity), n_years * n_ages)

  clear()
})

test_that("CatchAtAgePopulationDerivedQuantities Fill sets all fields to the given value", {
  pop_dq <- methods::new(CatchAtAgePopulationDerivedQuantities)
  pop_dq$Initialize(n_years, n_ages)
  fill_value <- 3.14
  pop_dq$Fill(fill_value)

  #' @description Test that Fill sets all total_landings_weight values to fill_value.
  for (i in 1:n_years) {
    expect_equal(pop_dq$total_landings_weight[i]$value, fill_value)
  }
  #' @description Test that Fill sets all mortality_F values to fill_value.
  for (i in 1:(n_years * n_ages)) {
    expect_equal(pop_dq$mortality_F[i]$value, fill_value)
  }
  #' @description Test that Fill sets all biomass values to fill_value.
  for (i in 1:(n_years + 1)) {
    expect_equal(pop_dq$biomass[i]$value, fill_value)
  }
  #' @description Test that Fill sets all numbers_at_age values to fill_value.
  for (i in 1:((n_years + 1) * n_ages)) {
    expect_equal(pop_dq$numbers_at_age[i]$value, fill_value)
  }

  clear()
})

test_that("CatchAtAgePopulationDerivedQuantities Fill defaults to 0.0", {
  pop_dq <- methods::new(CatchAtAgePopulationDerivedQuantities)
  pop_dq$Initialize(n_years, n_ages)
  pop_dq$Fill(3.14)
  #' @description Test that Fill with no arguments resets all total_landings_weight values to 0.
  pop_dq$Fill()
  for (i in 1:n_years) {
    expect_equal(pop_dq$total_landings_weight[i]$value, 0.0)
  }
  #' @description Test that Fill with no arguments resets all spawning_biomass values to 0.
  for (i in 1:(n_years + 1)) {
    expect_equal(pop_dq$spawning_biomass[i]$value, 0.0)
  }

  clear()
})

