### CatchAtAge ----
test_that("CatchAtAge constructor and GetId work correctly", {
  caa <- methods::new(CatchAtAge)
  #' @description Test that GetId returns 1 for the first CatchAtAge instance.
  expect_equal(caa$GetId(), 1)
  clear()
})

test_that("CatchAtAge AddPopulation runs without error for a valid or missing population id", {
  caa <- methods::new(CatchAtAge)
  #' @description Test that AddPopulation does not throw when called with a population id that has no corresponding live object (logs internally instead).
  expect_no_error(caa$AddPopulation(1))
  clear()
})

test_that("CatchAtAge IsReporting returns FALSE without an active TMB model", {
  caa <- methods::new(CatchAtAge)
  #' @description Test that IsReporting returns FALSE when no TMB model has been initialized.
  expect_false(caa$IsReporting())
  clear()
})

test_that("CatchAtAge InitializePopulationDerivedQuantities and GetPopulationDerivedQuantities work correctly", {
  caa <- methods::new(CatchAtAge)

  #' @description Test that InitializePopulationDerivedQuantities runs silently.
  expect_silent(caa$InitializePopulationDerivedQuantities(1, n_years, n_ages))

  pop_dq <- caa$GetPopulationDerivedQuantities(1)
  #' @description Test that GetPopulationDerivedQuantities returns an object with total_landings_weight sized to n_years.
  expect_equal(length(pop_dq$total_landings_weight), n_years)
  #' @description Test that GetPopulationDerivedQuantities returns an object with mortality_F sized to n_years * n_ages.
  expect_equal(length(pop_dq$mortality_F), n_years * n_ages)
  #' @description Test that GetPopulationDerivedQuantities returns an object with numbers_at_age sized to (n_years + 1) * n_ages.
  expect_equal(length(pop_dq$numbers_at_age), (n_years + 1) * n_ages)
  #' @description Test that GetPopulationDerivedQuantities returns an object with biomass sized to n_years + 1.
  expect_equal(length(pop_dq$biomass), n_years + 1)
  #' @description Test that GetPopulationDerivedQuantities returns an object with expected_recruitment sized to n_years + 1.
  expect_equal(length(pop_dq$expected_recruitment), n_years + 1)

  clear()
})

test_that("CatchAtAge InitializeFleetDerivedQuantities and GetFleetDerivedQuantities work correctly", {
  caa <- methods::new(CatchAtAge)

  #' @description Test that InitializeFleetDerivedQuantities runs silently.
  expect_silent(caa$InitializeFleetDerivedQuantities(1, n_years, n_ages, n_lengths))

  fleet_dq <- caa$GetFleetDerivedQuantities(1)
  #' @description Test that GetFleetDerivedQuantities returns an object with landings_numbers_at_age sized to n_years * n_ages.
  expect_equal(length(fleet_dq$landings_numbers_at_age), n_years * n_ages)
  #' @description Test that GetFleetDerivedQuantities returns an object with landings_weight sized to n_years.
  expect_equal(length(fleet_dq$landings_weight), n_years)
  #' @description Test that GetFleetDerivedQuantities returns an object with agecomp_proportion sized to n_years * n_ages.
  expect_equal(length(fleet_dq$agecomp_proportion), n_years * n_ages)
  #' @description Test that GetFleetDerivedQuantities returns an object with index_numbers_at_length sized to n_years * n_lengths.
  expect_equal(length(fleet_dq$index_numbers_at_length), n_years * n_lengths)
  #' @description Test that GetFleetDerivedQuantities returns an object with expected_catch sized to n_years.
  expect_equal(length(fleet_dq$expected_catch), n_years)

  clear()
})

## Edge handling ----
test_that("CatchAtAge GetPopulationDerivedQuantities after AddPopulation initializes the entry", {
  caa <- methods::new(CatchAtAge)
  caa$AddPopulation(1)
  caa$InitializePopulationDerivedQuantities(1, n_years, n_ages)

  pop_dq <- caa$GetPopulationDerivedQuantities(1)
  #' @description Test that GetPopulationDerivedQuantities works after AddPopulation and Initialize and returns correctly sized spawning_biomass.
  expect_equal(length(pop_dq$spawning_biomass), n_years + 1)

  clear()
})

## Error handling ----
test_that("CatchAtAge returns errors for unregistered derived quantity IDs", {
  caa <- methods::new(CatchAtAge)

  #' @description Test that GetPopulationDerivedQuantities throws when the population_id has not been initialized.
  expect_error(caa$GetPopulationDerivedQuantities(99))
  #' @description Test that GetFleetDerivedQuantities throws when the fleet_id has not been initialized.
  expect_error(caa$GetFleetDerivedQuantities(99))

  clear()
})
